	 */
	public static <E, K, V> Map<K, V> toMap(Collection<E> collection, Function<E, K> key, Function<E, V> value, boolean isParallel) {
<COVER>		if (CollUtil.isEmpty(collection)) {
			return MapUtil.newHashMap(0);
		}
