	 * @since 5.7.17
	 */
	public static <T extends Collection<E>, E> T removeWithAddIf(T targetCollection, T resultCollection, Predicate<? super E> predicate) {
<COVER>		Objects.requireNonNull(predicate);
<COVER>		final Iterator<E> each = targetCollection.iterator();
<COVER>		while (each.hasNext()) {
<COVER>			E next = each.next();
<COVER>			if (predicate.test(next)) {
<COVER>				resultCollection.add(next);
<COVER>				each.remove();
			}
		}
<COVER>		return resultCollection;
	}

