	 * @param collection 集合，用于初始化Set
	 * @return HashSet对象
	 */
	public static <T> HashSet<T> newHashSet(boolean isSorted, Collection<T> collection) {
<COVER>		return isSorted ? new LinkedHashSet<>(collection) : new HashSet<>(collection);
