	 * @return 移除结果的集合
	 * @since 5.7.17
	 */
	public static <T extends Collection<E>, E> List<E> removeWithAddIf(T targetCollection, Predicate<? super E> predicate) {
		final List<E> removed = new ArrayList<>();
		removeWithAddIf(targetCollection, removed, predicate);
		return removed;
	}

